perform:
if (object.properties.worn) {
  return lib.result("You are already wearing the " + lib.ref(object) + ".");
}

return {
  output: "You slip into the silver-gray jumpsuit. It's surprisingly light and seals with a soft magnetic hiss along the front. As you smooth the fabric, you notice a small, unusual lump in the inner lining near the mission patch, but the suit fits perfectly.",
  events: [
    lib.setEvent(object.id, {
      property: "worn",
      value: true,
      description: "Vapor Suit is now worn."
    })
  ]
};

var output = "You run your hands over the silver-gray fabric of the jumpsuit. It's remarkably thin but feels durable. As you check the inner lining near the mission patch, your fingers catch on a small, seamless slit—a hidden pocket.";

if (!store["item:data-chip"]) {
  output += " Inside, you feel the hard edge of a tiny data chip.";
  return {
    output: output,
    events: [
      lib.createEvent("item:data-chip", {
        tags: ["portable"],
        properties: {
          name: "small data chip",
          description: "A fingernail-sized sliver of translucent crystalline material. It catches the light with a faint amber glow.",
          aliases: ["chip", "data chip"],
          location: object.id
        },
        description: "Discovered a data chip in the suit lining"
      })
    ]
  };
}

return lib.result(output + " The hidden pocket is now empty.");

if (!indirect || indirect.id !== 'item:status-panel') {
  return lib.result('You can\'t plug that in there.');
}

return {
  output: 'You slide the translucent sliver into a thin, recessed slot at the base of the Status Panel. The display flickers, the amber glow of the chip bleeding into the screen\'s text. A new menu layer appears: HIBERNATION LOGS - BAY C-1 TO C-12. Most bays show standard signatures, but Bay C-4 shows a manual revival event dated 242 years ago. The occupant is listed as "DEPARTED."',
  events: [
    lib.setEvent(indirect.id, {
      property: 'description',
      value: 'The panel now displays a detailed log overlay from the data chip. Among the rows of green text, one entry in BAY C-4 stands out in bright amber: OCCUPANT REVIVED - 242 YEARS AGO - STATUS: DEPARTED.',
      description: 'Panel updated with chip data'
    }),
    lib.setEvent(object.id, {
      property: 'location',
      value: indirect.id,
      description: 'Chip inserted into panel'
    })
  ]
};

var carried = lib.carried();
var tools = carried.filter(function(e) { return e.tags.has('tool') || e.tags.has('electronic'); });

if (object.properties.systemStatus === 'offline') {
  return lib.result('The panel is dead. Hacking a cold circuit won\'t get you anywhere.');
}

if (tools.length > 0) {
  return {
    output: 'Using the ' + lib.ref(tools[0]) + ', you bypass the security layer. The screen flicker-cycles through hibernation logs for the entire sector. One entry pulses amber: BAY C-4, OCCUPANT REVIVED - 242 YEARS AGO. There is no death certificate on file.',
    events: [lib.setEvent(object.id, { property: 'systemStatus', value: 'operational', description: 'Deep access granted' })]
  };
} else {
  return lib.result('You tap into the maintenance sub-menus with a series of rhythmic presses. The panel resists a full override without proper tools, but you manage to catch a glimpse of a sector map showing an anomalous power draw in Bay C-4.');
}
